class APITracker {
    static let shared = APITracker()
    
    private init() {}
    
    func trackRequest(url: String, method: String, headers: [String: String], body: Data?, userId: String?, authToken: String?) {
        var bodyDict: [String: Any]?
        if let body = body {
            bodyDict = try? JSONSerialization.jsonObject(with: body, options: []) as? [String: Any]
        }
        
        var allHeaders = headers
        if let token = authToken {
            allHeaders["Authorization"] = "Bearer \(token)"
        }
        
        AnalyticsDebugger.shared.logAPICall(
            endpoint: url,
            method: method,
            headers: allHeaders,
            body: bodyDict,
            userId: userId
        )
    }
    
    func trackResponse(url: String, statusCode: Int, data: Data?, error: Error?, userId: String?) {
        var responseDict: [String: Any]?
        if let data = data {
            responseDict = try? JSONSerialization.jsonObject(with: data, options: []) as? [String: Any]
        }
        
        AnalyticsDebugger.shared.logAPIResponse(
            endpoint: url,
            statusCode: statusCode,
            response: responseDict,
            error: error,
            userId: userId
        )
    }
}

